import { useQuery } from '@tanstack/react-query';
import React, { useEffect, useState } from 'react'
import { useNavigate, useParams } from 'react-router-dom'
import { Img_URL, fetchSearch } from '../../utils/fetchApi';
import '../SearchItem/search.scss';

const Search = () => {
  const {searchTerm} = useParams();
  const navigate= useNavigate();
  const [page,setPage]= useState(1);

  const Page= page;
  const pageHandler =()=>{
    setPage(page+1);
  }

    const {isLoading,isError,error,data:searchItem,refetch}=useQuery({
      queryKey:['searchItem'],
      queryFn: ()=> fetchSearch(`${searchTerm},${Page}`)
      .then((res)=>{
        console.log(res);
        return res.results;
      }
        ),
    })

    useEffect(()=>{
      refetch();
    },[searchTerm,refetch])

  if (isLoading) {
    return (
      <div className="loading">
        <h1>Loading</h1>
      </div>
    );
  } else if (isError) {
    return (
      <div className="error">
        <p>{error.message}</p>
      </div>
    );
  }else
  return (
    <section className='search'>
      {
        searchItem[0]==null?<h2>Sorry '{searchTerm}' Not Found...</h2>:
        searchItem.map((item)=>(
         <div key={item.id} onClick={()=> navigate(`/movie/${item.id}`)}>
          { 
            item.poster_path && <img src={ `${Img_URL}${item.poster_path}`} alt="" />
          }
          <aside>
          <h1>{item.title}</h1>
          <p>{item.overview}</p>
          </aside>
        </div>
        ))
      }
      <button onclick={()=> pageHandler()}>Next</button>
    </section>
  )
    }

export default Search
